function specialMix(...data) {
  sum = 0;
  for (let i = 0; i < data.length; i++) {
    let num = parseInt(data[i]);
    if (isNaN(num)) {
      num = 0;
    }
    sum += +num;
  }
  return sum == 0 ? "All Is Strings" : sum;
}

